def first_missing_positive(xs):
    n = len(xs)
    # Place each number in its correct position (1 at index 0, 2 at index 1, etc.)
    for i in range(n):
        while 1 <= xs[i] <= n and xs[xs[i] - 1] != xs[i]:
            # Swap xs[i] to its correct position
            correct_pos = xs[i] - 1
            xs[i], xs[correct_pos] = xs[correct_pos], xs[i]
    # Find the first index where the value is not i+1
    for i in range(n):
        if xs[i] != i + 1:
            return i + 1
    return n + 1
